import{_ as a,a as d,b as e}from"./chunks/配置容量限制.DkdWbdOw.js";import{_ as l,o as r,c as o,a2 as i}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"Cloudflare R2 채널 추가","description":"","frontmatter":{},"headers":[],"relativePath":"ko-KR/upload/cloudflare-r2.md","filePath":"ko-KR/upload/cloudflare-r2.md","lastUpdated":1781962217000}'),c={name:"ko-KR/upload/cloudflare-r2.md"};function n(h,t,u,s,p,f){return r(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="cloudflare-r2-채널-추가" tabindex="-1">Cloudflare R2 채널 추가 <a class="header-anchor" href="#cloudflare-r2-채널-추가" aria-label="Permalink to &quot;Cloudflare R2 채널 추가&quot;">​</a></h1><p>Cloudflare R2 채널은 Cloudflare R2 버킷에 파일을 저장하기 위한 설정입니다.</p><h2 id="적합한-경우" tabindex="-1">적합한 경우 <a class="header-anchor" href="#적합한-경우" aria-label="Permalink to &quot;적합한 경우&quot;">​</a></h2><ul><li>Cloudflare Workers와 같은 생태계에서 저장소도 함께 관리하고 싶을 때.</li><li>R2 버킷을 ImgBed의 기본 저장소로 쓰고 싶을 때.</li><li>커스텀 도메인이나 CDN과 함께 이미지 배포를 구성하고 싶을 때.</li></ul><h2 id="준비할-것" tabindex="-1">준비할 것 <a class="header-anchor" href="#준비할-것" aria-label="Permalink to &quot;준비할 것&quot;">​</a></h2><table tabindex="0"><thead><tr><th>준비 항목</th><th>용도</th></tr></thead><tbody><tr><td>Cloudflare 계정</td><td>R2와 API Token 관리</td></tr><tr><td>R2 버킷</td><td>실제 파일 저장 위치</td></tr><tr><td>Account ID</td><td>R2 작업에 필요</td></tr><tr><td>API Token</td><td>버킷 읽기/쓰기 권한</td></tr><tr><td>커스텀 도메인</td><td>선택 사항. 공개 URL을 정리할 때 사용</td></tr></tbody></table><h2 id="버킷-만들기" tabindex="-1">버킷 만들기 <a class="header-anchor" href="#버킷-만들기" aria-label="Permalink to &quot;버킷 만들기&quot;">​</a></h2><p>Cloudflare Dashboard에서 <code>R2 Object Storage</code>를 열고 새 버킷을 만듭니다.</p><p><img src="'+a+'" alt="R2 버킷 만들기" loading="lazy"></p><p>버킷 이름은 ImgBed 설정에 그대로 입력해야 하므로 정확히 기록해 둡니다.</p><h2 id="account-id-확인" tabindex="-1">Account ID 확인 <a class="header-anchor" href="#account-id-확인" aria-label="Permalink to &quot;Account ID 확인&quot;">​</a></h2><p>Cloudflare 계정 화면에서 Account ID를 확인합니다.</p><p><img src="'+d+'" alt="Account ID" loading="lazy"></p><h2 id="imgbed에-입력하기" tabindex="-1">ImgBed에 입력하기 <a class="header-anchor" href="#imgbed에-입력하기" aria-label="Permalink to &quot;ImgBed에 입력하기&quot;">​</a></h2><p>업로드 설정에서 <code>채널 추가</code>를 열고 <code>Cloudflare R2</code>를 선택합니다.</p><table tabindex="0"><thead><tr><th>항목</th><th>입력 내용</th></tr></thead><tbody><tr><td>채널 이름</td><td>알아보기 쉬운 이름</td></tr><tr><td>Account ID</td><td>Cloudflare Account ID</td></tr><tr><td>Bucket 이름</td><td>생성한 R2 버킷 이름</td></tr><tr><td>API Token</td><td>R2 접근 권한이 있는 Token</td></tr><tr><td>커스텀 도메인</td><td>선택 사항</td></tr><tr><td>저장 디렉터리</td><td>보통 <code>imgbed</code></td></tr></tbody></table><h2 id="용량-제한" tabindex="-1">용량 제한 <a class="header-anchor" href="#용량-제한" aria-label="Permalink to &quot;용량 제한&quot;">​</a></h2><p>필요하면 용량 제한을 설정할 수 있습니다.</p><p><img src="'+e+'" alt="용량 제한" loading="lazy"></p><p>용량 제한을 켜면 설정한 상한과 임계값에 따라 해당 채널이 업로드 대상에서 제외될 수 있습니다.</p><h2 id="확인-방법" tabindex="-1">확인 방법 <a class="header-anchor" href="#확인-방법" aria-label="Permalink to &quot;확인 방법&quot;">​</a></h2><ol><li>저장 후 R2 채널 카드가 표시됩니다.</li><li>채널이 사용 상태인지 확인합니다.</li><li>테스트 이미지를 업로드합니다.</li><li>R2 버킷에 객체가 생성되었는지 확인합니다.</li><li>반환된 링크가 브라우저에서 열리는지 확인합니다.</li></ol><h2 id="자주-나는-오류" tabindex="-1">자주 나는 오류 <a class="header-anchor" href="#자주-나는-오류" aria-label="Permalink to &quot;자주 나는 오류&quot;">​</a></h2><ul><li>Account ID 또는 Bucket 이름이 틀림.</li><li>API Token에 대상 버킷 권한이 없음.</li><li>커스텀 도메인이 R2 버킷에 제대로 연결되지 않음.</li><li>용량 제한 때문에 업로드 대상에서 제외됨.</li></ul>',24)])])}const R=l(c,[["render",n]]);export{_ as __pageData,R as default};
